import { ShellStateProvider, useShellState } from '@medalsocial/meda'
import type { ReactNode } from 'react'

export function AppShellStateProvider({
  children,
  searchParams,
  setSearchParams,
  activeRail = 'home',
  selectionQueryParam = 'selection',
  storageKey = 'app.side-panel.width',
}: {
  children: ReactNode
  searchParams: URLSearchParams
  setSearchParams: (updater: (current: URLSearchParams) => URLSearchParams) => void
  activeRail?: string
  selectionQueryParam?: string
  storageKey?: string
}) {
  return (
    <ShellStateProvider
      adapter={{ searchParams, setSearchParams }}
      initialActiveRail={activeRail}
      selectionQueryParam={selectionQueryParam}
      sidePanelWidthStorageKey={storageKey}
    >
      {children}
    </ShellStateProvider>
  )
}

export { useShellState as useMedaShellState }
